DROP TABLE IF EXISTS `account_transactions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `account_transactions` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `account_id` int(11) NOT NULL,
  `type` enum('debit','credit') NOT NULL,
  `sub_type` enum('opening_balance','fund_transfer','deposit','debit') DEFAULT NULL,
  `amount` decimal(22,4) NOT NULL,
  `reff_no` varchar(191) DEFAULT NULL,
  `operation_date` datetime NOT NULL,
  `created_by` int(11) NOT NULL,
  `transaction_id` int(11) DEFAULT NULL,
  `expense_transaction_payment_id` int(10) unsigned DEFAULT NULL,
  `hrm_transaction_payment_id` int(10) unsigned DEFAULT NULL,
  `transaction_payment_id` int(10) unsigned DEFAULT NULL,
  `transfer_transaction_id` int(11) DEFAULT NULL,
  `note` text DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `account_transactions_account_id_index` (`account_id`),
  KEY `account_transactions_transaction_id_index` (`transaction_id`),
  KEY `account_transactions_transfer_transaction_id_index` (`transfer_transaction_id`),
  KEY `account_transactions_created_by_index` (`created_by`),
  KEY `account_transactions_type_index` (`type`),
  KEY `account_transactions_sub_type_index` (`sub_type`),
  KEY `account_transactions_transaction_payment_id_foreign` (`transaction_payment_id`),
  KEY `account_transactions_hrm_transaction_payment_id_foreign` (`hrm_transaction_payment_id`),
  KEY `account_transactions_expense_transaction_payment_id_foreign` (`expense_transaction_payment_id`),
  CONSTRAINT `account_transactions_expense_transaction_payment_id_foreign` FOREIGN KEY (`expense_transaction_payment_id`) REFERENCES `expense_transaction_payments` (`id`) ON DELETE CASCADE,
  CONSTRAINT `account_transactions_hrm_transaction_payment_id_foreign` FOREIGN KEY (`hrm_transaction_payment_id`) REFERENCES `hrm_transaction_payments` (`id`) ON DELETE CASCADE,
  CONSTRAINT `account_transactions_transaction_payment_id_foreign` FOREIGN KEY (`transaction_payment_id`) REFERENCES `fee_transaction_payments` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=254 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

