INSERT INTO `front_about_us` VALUES (1,'Mr.Kamod Tiwari','publish','Principal\'s Message','Mr.Kamod Tiwari','<p><strong>Education is a journey to explore experiment and explain the meaning of life.</strong></p>\r\n<p style=\"text-align: left;\">&nbsp; Each movement unfolds into a beautiful expression o<em>f life&rsquo;s bounty in laughter, cheer, conc</em>ern and dream of our students as they move towards&nbsp; &nbsp; &nbsp; &nbsp;excellence in Education and all around development.</p>\r\n<p style=\"padding-left: 40px;\">Dear students, you are the central point of the whole exercise of running the school.&nbsp; We at school believe in developing a person with integrity, good values, positive attitude and strength of character, a person with strong will and determination to succeed using fair means and make the personal significant contribution towards positive growth of community, society and the nation.&nbsp; The school would help you with full opportunity to move on the path of self development &amp; success by providing you a unique teaching learning environment&nbsp; in pursuit of all round excellence.</p>\r\n<p style=\"padding-left: 40px;\">At Shree Juddha Secondry School, Kalindi, We not only believe in having students&nbsp; to be trailblazer in academics but also in topping and show-casing their boundless talents.</p>\r\nDear students,\r\n\r\nYou are the central point of the whole exercise of running the school. We, at school believe in developing a person with integrity, good values, positive attitude and strength of character, a person with strong will and determination to succeed using fair means and make the personal significant contribution towards positive growth of community, society and the nation. Shree Juddha Secondry School & College would help you with full opportunity to move on the path of self-development & success by providing you a unique teaching learning environment in pursuit of all round excellence. At Shree Juddha Secondry School, We not only believe in having students to be trailblazer in academics but also in topping and show-casing their boundless talents.','speendad.jpg','2023-01-10 13:08:34','2023-01-10 13:08:34');
