INSERT INTO `front_gallery_contents` VALUES (8,'happy-grandparents-day-2023','1675362495_327880414_865635357827142_1046002777294438480_n.jpg',1,'HAPPY GRANDPARENTS DAY 2023','Chief Guest\r\nMr. Pashupati  Bikram shah and Ms. Usha shah.\r\nCelebrating Grandparents day to honor the importance of Grandparents in our lives! Growing up with Grandparents is a blessing, as they provide unconditional love and guidance to children, helping them to become better individuals. We are so lucky to have them in our lives!','publish','{\"1\":{\"image\":\"1675362624_328934789_3542736122606591_8160072749790811319_n.jpg\",\"type\":\"1\",\"video_url\":null,\"date\":\"2023-02-02 23:30:24\"},\"2\":{\"image\":\"1675362624_328874607_508119638135999_2286227672210800586_n.jpg\",\"type\":\"1\",\"video_url\":null,\"date\":\"2023-02-02 23:30:24\"},\"3\":{\"image\":\"1675362624_328649058_561290769356308_3382973460486518571_n.jpg\",\"type\":\"1\",\"video_url\":null,\"date\":\"2023-02-02 23:30:24\"},\"4\":{\"image\":\"1675362624_327582793_596400995624592_7306978271567759757_n.jpg\",\"type\":\"1\",\"video_url\":null,\"date\":\"2023-02-02 23:30:24\"},\"5\":{\"image\":\"1675362624_327880414_865635357827142_1046002777294438480_n.jpg\",\"type\":\"1\",\"video_url\":null,\"date\":\"2023-02-02 23:30:24\"}}','2023-02-03 04:28:15','2023-02-03 04:30:24');
