INSERT INTO `front_sliders` VALUES (4,'publish','HAPPY GRANDPARENTS DAY 2023','Chief Guest\r\nMr. Pashupati  Bikram shah and Ms. Usha shah.\r\nCelebrating Grandparents day to honor the importance of Grandparents in our lives! Growing up with Grandparents is a blessing, as they provide unconditional love and guidance to children, helping them to become better individuals. We are so lucky to have them in our lives!','1675361531_327880414_865635357827142_1046002777294438480_n.jpg','More','https://gyandaacademy.illuminatetech.net/gallery-happy-grandparents-day-2023/8','2023-02-03 03:47:29','2023-02-03 04:36:25'),(5,'publish','Gyanda Academy hosted a program for over 500 students','Gyanda Academy hosted a program for over 500 students','1675362817_328450067_682452003663506_7590066004042839022_n.jpg',NULL,NULL,'2023-02-03 04:33:37','2023-02-03 04:33:37');
