ate is  over .\nAccounts Manager: \n   Swat Collegiate',NULL,'Thank you from {business_name}',NULL,NULL,0,1,0,'2021-11-26 11:45:44','2021-11-26 11:45:44'),(9,'student_attendance_absent_sms',NULL,'Dear Parrents\nMr/Miss {student_name}  Class\n{current_class} is absent from school today\nDate: {clock_in_time}.\n\nPrincipal\n      Collegiate  \n',NULL,'Thank you from {business_name}',NULL,NULL,0,1,0,'2021-11-26 21:45:44','2021-11-26 21:45:44');
