DROP TABLE IF EXISTS `users`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `users` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `surname` varchar(191) NOT NULL,
  `user_type` enum('admin','other','teacher','guardian','staff','student') DEFAULT NULL,
  `hook_id` int(10) unsigned DEFAULT NULL,
  `first_name` varchar(191) DEFAULT NULL,
  `last_name` varchar(191) DEFAULT NULL,
  `email` varchar(191) NOT NULL,
  `email_verified_at` timestamp NULL DEFAULT NULL,
  `password` varchar(191) NOT NULL,
  `remember_token` varchar(100) DEFAULT NULL,
  `system_settings_id` int(10) unsigned DEFAULT NULL,
  `campus_id` int(10) unsigned DEFAULT NULL,
  `image` text DEFAULT NULL,
  `language` varchar(250) NOT NULL DEFAULT 'en',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `users_email_unique` (`email`),
  KEY `users_system_settings_id_foreign` (`system_settings_id`),
  CONSTRAINT `users_system_settings_id_foreign` FOREIGN KEY (`system_settings_id`) REFERENCES `system_settings` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=162 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
